actions.script:
// Notice we query 'MultipleChoiceDetail' (the View) instead of the individual tables.
// The Entity Facade does the SQL JOIN automatically.
questionList = ec.entity.find("intelliprep.quiz.MultipleChoiceDetail")
    .condition("difficultyLevel", level)
    .orderBy("-questionId") // Order descending
    .list()

if (questionList) {
    ec.logger.info("Found " + questionList.size() + " questions at difficulty level " + level)
}

// 1. Fetch the specific spoke record
def spokeRecord = ec.entity.find("intelliprep.quiz.MultipleChoice")
    .condition("questionId", questionId)
    .one()

// 2. Modify and Update
if (spokeRecord != null) {
    spokeRecord.optionA = newOptionA
    spokeRecord.update()
    ec.logger.info("Updated Option A for Question: " + questionId)
} else {
    ec.message.addError("Question ID not found.")
}
